parameters.jsCode:
const input = $input.first();

const binaries = input.binary || {};
const json = input.json || {};

return Object.entries(binaries).map(([key, value]) => ({
  json: {
    ...json,
    binary_field_name: key,
    fileName: value.fileName,
    mimeType: value.mimeType,
    fileExtension: value.fileExtension,
  },
  binary: {
    data: value
  }
}));

// 1) Get array of text blocks from the Aggregate node
let arr = $json.data || [];

// 2) Join all text pieces into one long text string
let txt = arr.join(" ");

// 3) Remove markdown headings
txt = txt.replace(/^#{1,6}\s*/gm, "");

// 4) Remove tabs and newlines
txt = txt.replace(/[\t\r]+/g, " ");
txt = txt.replace(/\n+/g, " ");

// 5) Remove leftover markdown bullets, dashes, stars
txt = txt.replace(/[*•\-+]{1,2}\s*/g, "");

// 6) Remove multiple spaces
txt = txt.replace(/\s{2,}/g, " ").trim();

// 7) JSON-escape without wrapping in quotes
let jsonSafe = JSON.stringify(txt).slice(1, -1);

return {
  json_safe: jsonSafe
};

